  1	import React, { FC, useState } from 'react';
  2	import { useParams } from 'react-router-dom-v5-compat';
  3	
  4	import useClusterPreferences from '@catalog/CreateFromInstanceTypes/state/hooks/useClusterPreferences';
  5	import ListPageFilter from '@kubevirt-utils/components/ListPageFilter/ListPageFilter';
  6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  7	import {
  8	  paginationDefaultValues,
  9	  paginationInitialState,
 10	} from '@kubevirt-utils/hooks/usePagination/utils/constants';
 11	import { DataSourceModelRef } from '@kubevirt-utils/models';
 12	import useBootableVolumes from '@kubevirt-utils/resources/bootableresources/hooks/useBootableVolumes';
 13	import useHideDeprecatedBootableVolumes from '@kubevirt-utils/resources/bootableresources/hooks/useHideDeprecatedBootableVolumes';
 14	import { isEmpty } from '@kubevirt-utils/utils/utils';
 15	import {
 16	  K8sResourceCommon,
 17	  ListPageBody,
 18	  ListPageHeader,
 19	  useListPageFilter,
 20	  VirtualizedTable,
 21	} from '@openshift-console/dynamic-plugin-sdk';
 22	import { Pagination, Stack, StackItem } from '@patternfly/react-core';
 23	
 24	import BootableVolumeAddButton from './components/BootableVolumeAddButton';
 25	import BootableVolumesEmptyState from './components/BootableVolumesEmptyState';
 26	import BootableVolumesRow from './components/BootableVolumesRow';
 27	import useBootableVolumesColumns from './hooks/useBootableVolumesColumns';
 28	import useBootableVolumesFilters from './hooks/useBootableVolumesFilters';
 29	
 30	import '@kubevirt-utils/styles/list-managment-group.scss';
 31	
 32	const BootableVolumesList: FC = () => {
 33	  const { ns: namespace } = useParams<{ ns: string }>();
 34	  const { t } = useKubevirtTranslation();
 35	
 36	  const { bootableVolumes, dataImportCrons, error, loaded } = useBootableVolumes(namespace);
 37	  const [preferences] = useClusterPreferences();
 38	
 39	  const rowFilters = useBootableVolumesFilters();
 40	  const [data, filteredData, onFilterChange] = useListPageFilter(bootableVolumes, rowFilters);
 41	  const [pagination, setPagination] = useState(paginationInitialState);
 42	  const [columns, activeColumns, loadedColumns] = useBootableVolumesColumns(
 43	    pagination,
 44	    filteredData,
 45	    preferences,
 46	  );
 47	
 48	  useHideDeprecatedBootableVolumes(onFilterChange);
 49	
 50	  const onPageChange = ({ endIndex, page, perPage, startIndex }) => {
 51	    setPagination(() => ({
 52	      endIndex,
 53	      page,
 54	      perPage,
 55	      startIndex,
 56	    }));
 57	  };
 58	
 59	  if (loaded && isEmpty(bootableVolumes)) {
 60	    return <BootableVolumesEmptyState namespace={namespace} />;
 61	  }
 62	
 63	  return (
 64	    <>
 65	      <ListPageHeader title={t('Bootable volumes')}>
 66	        <BootableVolumeAddButton namespace={namespace} />
 67	      </ListPageHeader>
 68	
 69	      <ListPageBody>
 70	        <Stack hasGutter>
 71	          <StackItem>{t('View and manage available bootable volumes.')}</StackItem>
 72	
 73	          <StackItem className="list-managment-group">
 74	            <ListPageFilter
 75	              columnLayout={{
 76	                columns: columns?.map(({ additional, id, title }) => ({
 77	                  additional,
 78	                  id,
 79	                  title,
 80	                })),
 81	                id: DataSourceModelRef,
 82	                selectedColumns: new Set(activeColumns?.map((col) => col?.id)),
 83	                type: t('DataSource'),
 84	              }}
 85	              onFilterChange={(...args) => {
 86	                onFilterChange(...args);
 87	                setPagination((prevPagination) => ({
 88	                  ...prevPagination,
 89	                  endIndex: prevPagination?.perPage,
 90	                  page: 1,
 91	                  startIndex: 0,
 92	                }));
 93	              }}
 94	              data={data}
 95	              loaded={loaded && loadedColumns}
 96	              rowFilters={rowFilters}
 97	            />
 98	            {!isEmpty(filteredData) && (
 99	              <Pagination
100	                onPerPageSelect={(_e, perPage, page, startIndex, endIndex) =>
101	                  onPageChange({ endIndex, page, perPage, startIndex })
102	                }
103	                onSetPage={(_e, page, perPage, startIndex, endIndex) =>
104	                  onPageChange({ endIndex, page, perPage, startIndex })
105	                }
106	                className="list-managment-group__pagination"
107	                isLastFullPageShown
108	                itemCount={filteredData?.length}
109	                page={pagination?.page}
110	                perPage={pagination?.perPage}
111	                perPageOptions={paginationDefaultValues}
112	              />
113	            )}
114	          </StackItem>
115	
116	          <VirtualizedTable<K8sResourceCommon>
117	            EmptyMsg={() => (
118	              <div className="pf-v6-u-text-align-center" id="no-bootable-volumes-msg">
119	                {t('No bootable volumes found')}
120	              </div>
121	            )}
122	            rowData={{
123	              dataImportCrons,
124	              preferences,
125	            }}
126	            columns={activeColumns}
127	            data={filteredData}
128	            loaded={loaded && loadedColumns}
129	            loadError={error}
130	            Row={BootableVolumesRow}
131	            unfilteredData={data}
132	          />
133	        </Stack>
134	      </ListPageBody>
135	    </>
136	  );
137	};
138	
139	export default BootableVolumesList;

